keep_lib() {
  for i in ${1}; do
    SFXLIBS="$(echo "$SFXLIBS" | awk -v i="$i" '{gsub(" *[^ ]*" i "\\.so *", ""); print}' | grep -v '^$')"
  done
  [ -z "$KEEPLIBS" ] && KEEPLIBS="$1" || KEEPLIBS="$KEEPLIBS $1"
}
proc_fx_intf() {
  local SFXLIBS LIBRS TMP SP LN
  case $1 in
  *.conf)
    SFXLIBS="$(sed -n "/^libraries {/,/^}/ {/^ *path / {s|.*/\(.*.so\)|\1|g;p}}" "$1")"; LIBRS="$(sed -n "/^libraries {/,/^}/ {/^libraries {/d;/^ *#/d;/^ *.*{/{s/^ *//;s/ {.*//;p}}" "$1")"
    for i in ${KEEPLIBS}; do
      SFXLIBS="$(echo "$SFXLIBS" | awk -v i="$i" '{gsub(" *" i "\\.so *", " "); if ($0 !~ /^[[:space:]]*$/) print}')"; TMP="$(awk -v i="$i" '/^libraries {/,/^}/ {if ($0 ~ "path .*/" i ".so") {print NR}}' "$1")"; TMP="$((TMP - 1))"; [ "$TMP" == "-1" ] && continue; TMP="$(awk 'NR=='"$TMP"' {gsub(/^ +/, ""); gsub(/ {/, ""); print}' "$1")"; LIBRS="$(echo "$LIBRS" | awk -v TMP="$TMP" '{gsub(" *" TMP " *", " "); if ($0 !~ /^[[:space:]]*$/) print}')"
    done
    for i in ${LIBRS}; do
      SP="$(sed -n "/^libraries {/,/^}/ {/^ *$i/p}" "$1" | sed -r "s/( *).*/\1/")"; sed -i "/^libraries {/,/^}/ {/^$SP$i {/,/^$SP}/d}" "$1"
      sed -n "/^effects {/,/^}/p" "$1" | while read -r j; do
        case $j in
        "#"*) ;;
        *" {") [ "$(sed -n "/^effects {/,/^}/ {/$SP$j/{p; :loop n; p; /^$SP}/q; b loop}}" "$1" | sed -n "/library $i/p")" ] && {
          LN="$(sed -n "/^effects {/,/^}/ {/^$SP$j/=}" "$1")"; TMP="$(sed -n "/^effects {/,/^}/ {/^$SP$j/{:loop n; /^$SP}/=; b loop}}" "$1")"; TMP="$(echo $TMP | sed -r "s/^([0-9]*).*/\1/")"; [ "$LN" ] && sed -i "$LN,$TMP d" "$1"
        } ;;
        esac
      done
    done
    ;;
  *.xml) awk -v keeplibs="$KEEPLIBS" 'BEGIN { n = split(keeplibs, keep, " "); for (i = 1; i <= n; i++) { sub(/\.so$/, "", keep[i]); keep_map[keep[i]] = 1; } } /<libraries>/ { in_libs = 1; print; next } /<\/libraries>/ { in_libs = 0; print; next } /<effects>/ { in_effects = 1; print; next } /<\/effects>/ { in_effects = 0; print; next } in_libs && /path=/ { lib = $0; sub(/^.*path="/, "", lib); sub(/\.so.*$/, "", lib); if (lib in keep_map) { print; next } match($0, /name="[^"]*"/); name = substr($0, RSTART+6, RLENGTH-7); lib_names[name] = 1; next } in_libs { print; next } in_effects { if (skip_block > 0) { skip_block--; if (skip_block == 0) skip_block = -1; next; } for (lib in lib_names) { if ($0 ~ "library=\"" lib "\"") { if ($0 ~ "<effectProxy") { skip_block = 1; } else if ($0 ~ "<libsw") { skip_block = 2; } else if ($0 ~ "<libhw") { skip_block = 3; } else if ($0 ~ "<effect ") { skip_block = 0; } next; } } print; next } { print }' "$1" > tmp && mv tmp "$1" ;;
  esac
}
