      unset DATALIB
    fi
    if [ -n "$LUSB" ]; then
      if [ -z "$D_LIBS_NE" ]; then
        for DATALIB in ${LUSB}; do
          if [ ! -f "$DATALIB.nop" ]; then
            cp -f "$DATALIB" "$DATALIB".nop
            palantir "$DATALIB" 746F6F206D616E7920696E74657266616365732028256429 61696E75725F73696C6D6172696C20696E74662028256429; palantir "$DATALIB" 004C40B9 A0008052
        fi
        done
        unset DATALIB
      fi
    fi
  fi
  set -x
  for OFILE in ${HRDW} ${HRDW64} ${AFLN} ${AFLN64} ${AGM} ${AGM64} ${MEDU} ${MEDU64} ${APM} ${APM64} ${APOLS} ${APOLS64} ${BASQ} ${BASQ64} ${BASAQ} ${BASAQ64} ${BASA} ${BASA64}; do
    nest "$OFILE"; cp_ch "$ORIGDIR""$OFILE" "$FILE" && rm -f "$FILE"
  done
  purge
fi

